"use client";

import { useMemo, useState } from "react";
import { useTranslations } from "next-intl";
import { Link } from "@/i18n/navigation";
import { ArrowUpRight, FileText, Search } from "lucide-react";
import type { CatalogManifest } from "@/lib/data/catalog-storage";

const HERO_IMAGE = "data:image/jpeg;base64,";

const THUMB_BACKGROUNDS = [
  "rgba(200,168,90,0.14)",
  "rgba(80,100,120,0.12)",
  "rgba(100,80,120,0.12)",
  "rgba(80,120,100,0.12)",
  "rgba(120,100,80,0.12)",
];

function thumbBgForCatalogId(id: string): string {
  let h = 0;
  for (let i = 0; i < id.length; i++) h = (h + id.charCodeAt(i) * (i + 1)) % 997;
  return THUMB_BACKGROUNDS[h % THUMB_BACKGROUNDS.length];
}

type AksanCatalogProps = {
  manifests: CatalogManifest[];
  loadError?: boolean;
};

export default function AksanCatalog({ manifests, loadError }: AksanCatalogProps) {
  const t = useTranslations("Catalog");

  const catalogIds = useMemo(
    () => Array.from(new Set(manifests.map((m) => m.catalogId))).sort(),
    [manifests],
  );
  const categories = useMemo(() => ["__ALL__", ...catalogIds], [catalogIds]);

  const [activeCategory, setActiveCategory] = useState("__ALL__");
  const [search, setSearch] = useState("");

  const filtered = useMemo(() => {
    return manifests.filter((m) => {
      const title = (m.title || m.catalogId).toLowerCase();
      const id = m.catalogId.toLowerCase();
      const matchCat = activeCategory === "__ALL__" || m.catalogId === activeCategory;
      const q = search.trim().toLowerCase();
      const matchSearch = !q || title.includes(q) || id.includes(q);
      return matchCat && matchSearch;
    });
  }, [manifests, activeCategory, search]);

  const yearFrom = (iso?: string) => {
    if (!iso) return new Date().getFullYear();
    const y = new Date(iso).getFullYear();
    return Number.isNaN(y) ? new Date().getFullYear() : y;
  };

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;1,300;1,400;1,500&family=DM+Sans:wght@300;400;500;600&display=swap');

        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

        .ck-root {
          font-family: 'DM Sans', sans-serif;
          min-height: 100vh;
          background: #FFFFFF;
          color: #0F1729;
        }

        /* ── HERO ── */
        .ck-hero {
          position: relative;
          min-height: min(80vh, 860px);
          overflow: hidden;
          display: flex;
          flex-direction: column;
          justify-content: flex-end;
        }

        .ck-hero-img {
          position: absolute;
          inset: 0;
          width: 100%;
          height: 100%;
          object-fit: cover;
          object-position: center right;
          transform: scale(1.04);
          animation: ck-breathe 24s ease-in-out infinite alternate;
        }
        @keyframes ck-breathe {
          from { transform: scale(1.04); }
          to   { transform: scale(1.09); }
        }

        .ck-hero-ov1 {
          position: absolute; inset: 0;
          background: linear-gradient(to bottom,
            rgba(8,8,10,0.08) 0%,
            rgba(8,8,10,0.04) 28%,
            rgba(8,8,10,0.50) 62%,
            rgba(8,8,10,0.93) 86%,
            rgba(8,8,10,1.00) 100%
          );
          z-index: 1;
        }
        .ck-hero-ov2 {
          position: absolute; inset: 0;
          background: linear-gradient(to right,
            rgba(8,8,10,0.85) 0%,
            rgba(8,8,10,0.28) 40%,
            rgba(8,8,10,0.00) 68%
          );
          z-index: 2;
        }
        .ck-hero-ov3 {
          position: absolute; inset: 0;
          background: radial-gradient(ellipse 55% 50% at 72% 48%,
            rgba(15,23,41,0.04) 0%,
            transparent 70%
          );
          z-index: 3;
        }

        .ck-hero-inner {
          position: relative;
          z-index: 10;
          max-width: 1440px;
          margin: 0 auto;
          width: 100%;
          padding: 8rem 2rem 5rem;
          display: flex;
          flex-direction: column;
          gap: 1.5rem;
        }
        @media (min-width: 768px) { .ck-hero-inner { padding: 9rem 3rem 5.5rem; } }
        @media (min-width: 1280px) {
          .ck-hero-inner {
            padding: 10rem 5rem 6rem;
            flex-direction: row;
            align-items: flex-end;
            justify-content: space-between;
          }
        }

        .ck-eyebrow {
          display: inline-flex; align-items: center; gap: 0.65rem;
          margin-bottom: 1.25rem;
        }
        .ck-eyebrow-line { width: 24px; height: 1px; background: rgba(200,168,90,0.35); }
        .ck-eyebrow-text {
          font-size: 0.64rem; font-weight: 500;
          letter-spacing: 0.28em; text-transform: uppercase;
          color: rgba(200,168,90,0.55);
        }

        .ck-page-heading {
          font-family: 'Cormorant Garamond', serif;
          font-weight: 300;
          font-size: clamp(3rem, 7vw, 6.5rem);
          line-height: 0.9;
          letter-spacing: -0.02em;
          color: rgba(255,255,255,0.96);
        }
        .ck-page-heading em {
          font-style: italic;
          font-weight: 400;
          color: #fff;
        }

        .ck-hero-right {
          max-width: 380px;
        }
        .ck-hero-desc {
          font-size: 0.88rem;
          font-weight: 300;
          line-height: 1.8;
          color: rgba(100,116,139,0.85);
          margin-bottom: 0;
        }

        /* ── FILTER BAR ── */
        .ck-filter-bar {
          background: #fff;
          border-bottom: 1px solid rgba(15,23,41,0.08);
          position: sticky;
          top: 72px;
          z-index: 50;
        }

        .ck-filter-inner {
          max-width: 1440px;
          margin: 0 auto;
          padding: 0 2rem;
          display: flex;
          align-items: center;
          justify-content: space-between;
          gap: 1rem;
          flex-wrap: wrap;
        }
        @media (min-width: 768px)  { .ck-filter-inner { padding: 0 3rem; } }
        @media (min-width: 1280px) { .ck-filter-inner { padding: 0 5rem; } }

        .ck-cats {
          display: flex;
          gap: 0;
          overflow-x: auto;
          scrollbar-width: none;
          flex: 1;
        }
        .ck-cats::-webkit-scrollbar { display: none; }

        .ck-cat-btn {
          font-family: 'DM Sans', sans-serif;
          font-size: 0.72rem;
          font-weight: 500;
          letter-spacing: 0.08em;
          text-transform: uppercase;
          color: rgba(15,23,41,0.95);
          background: none;
          border: none;
          border-bottom: 2px solid transparent;
          padding: 1.1rem 1.1rem;
          cursor: pointer;
          white-space: nowrap;
          transition: all 0.2s;
        }
        .ck-cat-btn:hover { color: #0F1729; }
        .ck-cat-btn.active {
          color: #0F1729;
          border-bottom-color: #C8A85A;
        }

        .ck-search-wrap {
          position: relative;
          flex-shrink: 0;
        }
        .ck-search-icon {
          position: absolute;
          left: 0.85rem; top: 50%;
          transform: translateY(-50%);
          pointer-events: none;
          color: rgba(71,85,105,0.9);
        }
        .ck-search {
          font-family: 'DM Sans', sans-serif;
          font-size: 0.82rem;
          font-weight: 300;
          color: #0F1729;
          background: #FFFFFF;
          border: 1px solid rgba(15,23,41,0.10);
          border-radius: 100px;
          padding: 0.55rem 1rem 0.55rem 2.2rem;
          outline: none;
          width: 200px;
          transition: all 0.25s;
        }
        .ck-search::placeholder { color: rgba(71,85,105,0.85); }
        .ck-search:focus {
          border-color: rgba(200,168,90,0.5);
          background: #fff;
          width: 240px;
          box-shadow: 0 0 0 3px rgba(200,168,90,0.08);
        }

        /* ── CATALOG GRID ── */
        .ck-main {
          max-width: 1440px;
          margin: 0 auto;
          padding: 4rem 2rem 6rem;
        }
        @media (min-width: 768px)  { .ck-main { padding: 4rem 3rem 6rem; } }
        @media (min-width: 1280px) { .ck-main { padding: 5rem 5rem 7rem; } }

        .ck-count {
          font-size: 0.7rem;
          font-weight: 500;
          letter-spacing: 0.14em;
          text-transform: uppercase;
          color: rgba(71,85,105,0.9);
          margin-bottom: 2.5rem;
        }

        .ck-grid {
          display: grid;
          grid-template-columns: 1fr;
          gap: 1.5rem;
        }
        @media (min-width: 640px)  { .ck-grid { grid-template-columns: 1fr 1fr; } }
        @media (min-width: 1024px) { .ck-grid { grid-template-columns: 1fr 1fr 1fr; } }

        /* ── CATALOG CARD ── */
        .ck-card {
          background: #fff;
          border: 1px solid rgba(15,23,41,0.08);
          border-radius: 14px;
          overflow: hidden;
          display: flex;
          flex-direction: column;
          transition: transform 0.3s ease, box-shadow 0.3s ease;
          animation: cardIn 0.4s ease both;
        }
        @keyframes cardIn {
          from { opacity:0; transform:translateY(14px); }
          to   { opacity:1; transform:translateY(0); }
        }
        .ck-card:hover {
          transform: translateY(-4px);
          box-shadow: 0 16px 48px rgba(0,0,0,0.07);
        }

        .ck-card-thumb {
          height: 160px;
          display: flex;
          align-items: center;
          justify-content: center;
          position: relative;
          border-bottom: 1px solid rgba(200,168,90,0.10);
          overflow: hidden;
        }

        .ck-card-thumb-img {
          width: 100%;
          height: 100%;
          object-fit: cover;
        }

        .ck-card-pages-icon {
          opacity: 0.18;
        }

        .ck-card-tag {
          position: absolute;
          top: 1rem; right: 1rem;
          font-size: 0.6rem;
          font-weight: 600;
          letter-spacing: 0.14em;
          text-transform: uppercase;
          color: #C8A85A;
          background: rgba(200,168,90,0.12);
          border: 1px solid rgba(200,168,90,0.22);
          border-radius: 100px;
          padding: 0.25rem 0.65rem;
        }

        .ck-card-body {
          padding: 1.5rem 1.5rem 0;
          flex: 1;
          display: flex;
          flex-direction: column;
          gap: 0.65rem;
        }

        .ck-card-cat {
          font-size: 0.62rem;
          font-weight: 600;
          letter-spacing: 0.18em;
          text-transform: uppercase;
          color: rgba(71,85,105,0.92);
        }

        .ck-card-title {
          font-family: 'Cormorant Garamond', serif;
          font-size: 1.3rem;
          font-weight: 500;
          line-height: 1.2;
          color: #0F1729;
          letter-spacing: -0.01em;
        }

        .ck-card-desc {
          font-size: 0.82rem;
          font-weight: 300;
          line-height: 1.7;
          color: rgba(15,23,41,0.92);
          flex: 1;
        }

        .ck-card-meta {
          display: flex;
          align-items: center;
          gap: 1rem;
          padding: 1rem 1.5rem;
          border-top: 1px solid rgba(200,168,90,0.10);
          margin-top: 1rem;
        }

        .ck-meta-item {
          font-size: 0.68rem;
          font-weight: 400;
          color: rgba(71,85,105,0.9);
          letter-spacing: 0.04em;
        }
        .ck-meta-dot {
          width: 3px; height: 3px;
          border-radius: 50%;
          background: rgba(15,23,41,0.14);
          flex-shrink: 0;
        }

        .ck-card-footer {
          padding: 0 1.5rem 1.5rem;
          display: flex;
          align-items: center;
          justify-content: flex-end;
        }

        .ck-view-btn {
          display: inline-flex;
          align-items: center;
          gap: 0.35rem;
          font-size: 0.72rem;
          font-weight: 500;
          letter-spacing: 0.08em;
          text-transform: uppercase;
          color: rgba(15,23,41,0.95);
          background: none;
          border: none;
          cursor: pointer;
          padding: 0;
          transition: color 0.2s;
          text-decoration: none;
        }
        .ck-view-btn:hover { color: #0F1729; }

        .ck-dl-btn {
          display: inline-flex;
          align-items: center;
          gap: 0.45rem;
          font-family: 'DM Sans', sans-serif;
          font-size: 0.72rem;
          font-weight: 500;
          letter-spacing: 0.08em;
          text-transform: uppercase;
          color: #FFFFFF;
          background: #0F1729;
          border: none;
          border-radius: 100px;
          padding: 0.6rem 1.1rem;
          cursor: pointer;
          transition: all 0.25s;
          white-space: nowrap;
          text-decoration: none;
        }
        .ck-dl-btn:hover {
          background: #1B2540;
          transform: translateY(-1px);
          box-shadow: 0 6px 20px rgba(0,0,0,0.18);
        }

        /* ── EMPTY STATE ── */
        .ck-empty {
          grid-column: 1/-1;
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          gap: 0.75rem;
          padding: 5rem 2rem;
          text-align: center;
          color: rgba(71,85,105,0.88);
        }
        .ck-empty-heading {
          font-family: 'Cormorant Garamond', serif;
          font-size: 1.75rem;
          font-weight: 400;
          color: rgba(15,23,41,0.88);
        }
        .ck-empty-text {
          font-size: 0.85rem;
          font-weight: 300;
          line-height: 1.7;
        }
      `}</style>

      <div className="ck-root">

        {/* HERO */}
        <div className="ck-hero">
          {/* eslint-disable-next-line @next/next/no-img-element */}
          <img src={HERO_IMAGE} alt="" className="ck-hero-img" />
          <div className="ck-hero-ov1" aria-hidden />
          <div className="ck-hero-ov2" aria-hidden />
          <div className="ck-hero-ov3" aria-hidden />
          <div className="ck-hero-inner">
            <div>
              <div className="ck-eyebrow">
                <div className="ck-eyebrow-line" />
                <span className="ck-eyebrow-text">{t("pageEyebrow")}</span>
              </div>
              <h1 className="ck-page-heading">
                {t("pageTitleLine1")}
                <br />
                <em>{t("pageTitleLine2")}</em>
              </h1>
            </div>
            <div className="ck-hero-right">
              <p className="ck-hero-desc">{t("pageSubtitle")}</p>
            </div>
          </div>
        </div>

        {/* FILTER BAR */}
        {!loadError && manifests.length > 0 ? (
          <div className="ck-filter-bar">
            <div className="ck-filter-inner">
              <div className="ck-cats">
                {categories.map((cat) => (
                  <button
                    key={cat}
                    type="button"
                    className={`ck-cat-btn${activeCategory === cat ? " active" : ""}`}
                    onClick={() => setActiveCategory(cat)}
                  >
                    {cat === "__ALL__" ? t("filterAll") : cat}
                  </button>
                ))}
              </div>
              <div className="ck-search-wrap">
                <Search size={13} className="ck-search-icon" />
                <input
                  className="ck-search"
                  placeholder={t("searchPlaceholder")}
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  aria-label={t("searchPlaceholder")}
                />
              </div>
            </div>
          </div>
        ) : null}

        {/* CATALOG GRID */}
        <div className="ck-main">
          {loadError ? (
            <div className="ck-empty">
              <FileText size={32} strokeWidth={1} />
              <h3 className="ck-empty-heading">{t("title")}</h3>
              <p className="ck-empty-text">{t("error")}</p>
            </div>
          ) : manifests.length === 0 ? (
            <div className="ck-empty">
              <FileText size={32} strokeWidth={1} />
              <h3 className="ck-empty-heading">{t("emptyTitle")}</h3>
              <p className="ck-empty-text">{t("emptySub")}</p>
            </div>
          ) : (
            <>
              <p className="ck-count">{t("foundCount", { count: filtered.length })}</p>

              <div className="ck-grid">
                {filtered.length === 0 ? (
                  <div className="ck-empty">
                    <FileText size={32} strokeWidth={1} />
                    <h3 className="ck-empty-heading">{t("noMatchTitle")}</h3>
                    <p className="ck-empty-text">{t("noMatchHint")}</p>
                  </div>
                ) : (
                  filtered.map((m, i) => {
                    const title = m.title || m.catalogId;
                    const cover = m.pages[0]?.thumbUrl || m.pages[0]?.url || null;
                    const bg = thumbBgForCatalogId(m.catalogId);
                    return (
                      <article
                        className="ck-card"
                        key={m.catalogId}
                        style={{ animationDelay: `${i * 60}ms` }}
                      >
                        <div
                          className="ck-card-thumb"
                          style={{ background: cover ? "#F4F1EA" : bg }}
                        >
                          {cover ? (
                            // eslint-disable-next-line @next/next/no-img-element
                            <img
                              src={cover}
                              alt=""
                              className="ck-card-thumb-img"
                              loading="lazy"
                            />
                          ) : (
                            <FileText
                              size={64}
                              strokeWidth={0.75}
                              color="#C8A85A"
                              className="ck-card-pages-icon"
                            />
                          )}
                        </div>

                        <div className="ck-card-body">
                          <span className="ck-card-cat">{m.catalogId}</span>
                          <h3 className="ck-card-title">{title}</h3>
                          <p className="ck-card-desc">{t("cardBlurb")}</p>
                        </div>

                        <div className="ck-card-meta">
                          <span className="ck-meta-item">
                            {m.totalPages} {t("toolbar.page")}
                          </span>
                          <div className="ck-meta-dot" />
                          <span className="ck-meta-item">{yearFrom(m.updatedAt)}</span>
                        </div>

                        <div className="ck-card-footer">
                          <Link
                            href={{
                              pathname: "/catalog/[catalogId]",
                              params: { catalogId: m.catalogId },
                            }}
                            className="ck-dl-btn"
                          >
                            {t("openCatalog")}
                            <ArrowUpRight size={12} strokeWidth={2} />
                          </Link>
                        </div>
                      </article>
                    );
                  })
                )}
              </div>
            </>
          )}
        </div>

      </div>
    </>
  );
}
